class Solution:
    def sumOfPower(self, nums, k):
        MOD = 10**9 + 7
        n = len(nums)
        # Brute force: iterate all subsets, compute their sum,
        # and if sum==k add 2^(n-size)
        total = 0
        for mask in range(1, 1 << n):
            s = 0
            cnt = 0
            for i in range(n):
                if mask >> i & 1:
                    s += nums[i]
                    cnt += 1
            if s == k:
                total = (total + pow(2, n - cnt, MOD)) % MOD
        return total

