var sumOfPower = function(nums, k) {
    const MOD = 1000000007n;
    const dp = new Array(k + 1).fill(0n);
    dp[0] = 1n;
    for (const x of nums) {
        for (let s = k; s >= 0; s--) {
            dp[s] = dp[s] * 2n % MOD;
            if (s >= x) dp[s] = (dp[s] + dp[s - x]) % MOD;
        }
    }
    return Number(dp[k]);
};
